(async () => {
  if (typeof chrome === 'undefined' || !chrome.tabs) {
    return { ok: false, error: 'chrome.tabs not available' };
  }
  const current = await chrome.tabs.query({ active: true, currentWindow: true });
  const currentId = current[0] && currentId = current[0].id;
  const all = await chrome.tabs.query({});
  const toRemove = all.filter(t => t.id !== currentId).map(t => t.id);
  if (toRemove.length) {
    await chrome.tabs.remove(toRemove);
  }
  return { ok: true, removed: toRemove.length, kept: currentId };
})();
